            <Stat label="Product Page Views" value={totalProductViews} icon="≡ƒæü∩╕Å" color={PRI} sub="Product interest signals" />
            <Stat label="Quote Requests" value={quoteRequests.length} icon="≡ƒôï" color="#16a34a" sub="Direct quote signals" />
            <Stat label="Top Product" value={cartAdds[0]?.[1]?.name || productViews[0]?.[1]?.name || 'ΓÇö'} icon="≡ƒÅå" color="#f59e0b" sub={cartAdds[0] ? `${cartAdds[0][1].count} cart adds` : ''} />
          </div>

          <Card>
            <h3 className="mb-4 text-sm font-semibold text-slate-900">≡ƒÆ╝ Financial Report ΓÇö Product Interest Summary</h3>
