import { createContext, useContext, useState } from 'react'
import { trackCartAdd } from '../hooks/useAnalytics'

const CartContext = createContext()

export function CartProvider({ children }) {
  const [cartItems, setCartItems] = useState([])

  function addToCart(item) {
    trackCartAdd(item.slug || item.id, item.name, item.quantity || 1, item.price)
    setCartItems(prev => {
      const existing = prev.find(i => i.id === item.id && i.size === item.size)
      if (existing) {
        return prev.map(i =>
          i.id === item.id && i.size === item.size
            ? { ...i, quantity: i.quantity + item.quantity }
            : i
        )
      }
      return [...prev, item]
    })
  }

  function updateQuantity(id, size, qty) {
    if (qty <= 0) {
      removeItem(id, size)
      return
    }
    setCartItems(prev =>
      prev.map(i => (i.id === id && i.size === size ? { ...i, quantity: qty } : i))
    )
  }

  function removeItem(id, size) {
    setCartItems(prev => prev.filter(i => !(i.id === id && i.size === size)))
  }

  function clearCart() {
    setCartItems([])
  }

  function getUnitPrice(product, qty) {
    const table = product.priceTable || []
    let price = 0
    for (const row of table) {
      if (qty >= row.qty) price = row.unitPrice
    }
    return price
  }

  function getDiscount(subtotal) {
    if (subtotal >= 100000) return 0.15
    if (subtotal >= 50000) return 0.10
    if (subtotal >= 20000) return 0.05
    return 0
  }

  const subtotal = cartItems.reduce((sum, i) => sum + i.price * i.quantity, 0)
  const discount = getDiscount(subtotal)
  const discountAmount = subtotal * discount
  const total = subtotal - discountAmount
  const totalItems = cartItems.reduce((sum, i) => sum + i.quantity, 0)

  return (
    <CartContext.Provider value={{
      cartItems, addToCart, updateQuantity, removeItem, clearCart,
      subtotal, discount, discountAmount, total, totalItems, getUnitPrice
    }}>
      {children}
    </CartContext.Provider>
  )
}

export function useCart() {
  return useContext(CartContext)
}

const ENDPOINT = '/api/analytics/track'

function getDevice() {
  const ua = navigator.userAgent
  if (/tablet|ipad|playbook|silk/i.test(ua)) return 'tablet'
  if (/mobile|android|iphone|ipod|blackberry|iemobile|opera mini/i.test(ua)) return 'mobile'
  return 'desktop'
}

export function track(event) {
  try {
    const payload = {
      ...event,
      device: getDevice(),
      referrer: document.referrer || '',
      userAgent: navigator.userAgent,
      timestamp: new Date().toISOString(),
    }
    fetch(ENDPOINT, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(payload),
    }).catch(() => {})
  } catch {}
}

export function trackPageView(page) {
  track({ type: 'pageview', page: page || window.location.pathname })
}

export function trackProductView(slug, name) {
  track({ type: 'product_view', slug, name, page: window.location.pathname })
}

export function trackCartAdd(slug, name, qty, price) {
  track({ type: 'cart_add', slug, name, qty: qty || 1, price, page: window.location.pathname })
}

export function trackInteraction(eventName, target) {
  track({ type: 'interaction', event: eventName, target, page: window.location.pathname })
}

export function trackQuoteRequest(slug, details) {
  track({ type: 'quote_request', slug, details, page: window.location.pathname })
}

import { useEffect } from 'react'

let cachedSEO = null
let seoPromise = null

const DEFAULT_TITLE = 'Sleekblue Media Houz ΓÇö Premium Printing. Zero Stress.'
const DEFAULT_DESC  = "Sleekblue Media Houz ΓÇö Nigeria's top printing and branding company in Owerri, Imo State. Die-cut stickers, flex banners, corporate branding and more."
const DEFAULT_KW    = 'printing company Nigeria, die cut stickers Owerri, flex banner printing, corporate branding Nigeria'

function fetchSEO() {
  if (cachedSEO) return Promise.resolve(cachedSEO)
  if (seoPromise) return seoPromise
  seoPromise = fetch('/api/seo')
    .then(r => r.ok ? r.json() : {})
    .then(d => { cachedSEO = d; return d })
    .catch(() => ({}))
  return seoPromise
}

function setMeta(name, content, attr = 'name') {
  if (!content) return
  let el = document.querySelector(`meta[${attr}="${name}"]`)
  if (!el) { el = document.createElement('meta'); el.setAttribute(attr, name); document.head.appendChild(el) }
  el.content = content
}

function removeMeta(name, attr = 'name') {
  const el = document.querySelector(`meta[${attr}="${name}"]`)
  if (el) el.remove()
}

function setLink(rel, href) {
  if (!href) {
    const el = document.querySelector(`link[rel="${rel}"]`)
    if (el) el.remove()
    return
  }
  let el = document.querySelector(`link[rel="${rel}"]`)
  if (!el) { el = document.createElement('link'); el.rel = rel; document.head.appendChild(el) }
  el.href = href
}

function applyMeta({ title, description, keywords, canonical, ogImage, ogType, noindex }) {
  document.title = title || DEFAULT_TITLE

  setMeta('description', description || DEFAULT_DESC)
  if (keywords) setMeta('keywords', keywords)

  setMeta('og:title',       title || DEFAULT_TITLE, 'property')
  setMeta('og:description', description || DEFAULT_DESC, 'property')
  setMeta('og:type',        ogType || 'website', 'property')
  setMeta('og:site_name',   'Sleekblue Media Houz', 'property')
  if (ogImage) setMeta('og:image', ogImage, 'property')

  setMeta('twitter:title',       title || DEFAULT_TITLE)
  setMeta('twitter:description', description || DEFAULT_DESC)
  if (ogImage) setMeta('twitter:image', ogImage)
  setMeta('twitter:card', ogImage ? 'summary_large_image' : 'summary')

  setLink('canonical', canonical || '')

  if (noindex) {
    setMeta('robots', 'noindex, nofollow')
  } else {
    removeMeta('robots')
  }
}

export function useSEO(pageKeyOrOptions, fallback = {}) {
  const isDirectOptions = typeof pageKeyOrOptions === 'object' && pageKeyOrOptions !== null

  useEffect(() => {
    if (isDirectOptions) {
      applyMeta(pageKeyOrOptions)
    } else {
      fetchSEO().then(seo => {
        const entry = seo[pageKeyOrOptions] || {}
        applyMeta({
          title:       entry.title       || fallback.title       || DEFAULT_TITLE,
          description: entry.description || fallback.description || DEFAULT_DESC,
          keywords:    entry.keywords    || fallback.keywords    || DEFAULT_KW,
          canonical:   entry.canonical   || fallback.canonical,
          ogImage:     entry.ogImage     || fallback.ogImage,
          noindex:     entry.noindex     || fallback.noindex,
        })
      })
    }
  }, [isDirectOptions ? JSON.stringify(pageKeyOrOptions) : pageKeyOrOptions])
}

export function useSEOKey(pageKey, fallback = {}) {
  return useSEO(pageKey, fallback)
}

export default useSEO

