    { id: 'sticker-prices', icon: '≡ƒÅ╖∩╕Å', label: 'Sticker Prices' },
    { id: 'blog',           icon: 'Γ£ì∩╕Å', label: 'Blog',       badge: counts.blogPosts || 0 },
    { id: 'about',          icon: '≡ƒôû', label: 'About Us' },
    { id: 'content',        icon: '≡ƒÄ¿', label: 'Content CMS' },
    { id: 'faq',            icon: 'Γ¥ô', label: 'FAQ Manager' },
    { id: 'seo',            icon: '≡ƒöì', label: 'SEO Manager' },
    { id: 'settings',       icon: 'ΓÜÖ∩╕Å', label: 'Site Settings' },
    { id: 'acceptances',    icon: '≡ƒôï', label: 'T&C Acceptances', badge: counts.acceptances },
    { id: 'security',       icon: '≡ƒöæ', label: 'Security' },
    { id: 'analytics',      icon: '≡ƒôê', label: 'Analytics' },
    { id: 'reports',        icon: '≡ƒÆ░', label: 'Reports' },
    { id: 'leads',          icon: '≡ƒô▓', label: 'WA Leads', badge: counts.leads || 0 },
    { id: 'promo-banner',   icon: '≡ƒôú', label: 'Promo Banner' },
    { id: 'activity-log',   icon: '≡ƒô£', label: 'Activity Log' },
    { id: 'seo-agent',      icon: '≡ƒñû', label: 'SEO Agent' },
    { id: 'growth',         icon: '≡ƒÜÇ', label: 'Growth Dashboard' },
    { id: 'newsletter',      icon: '≡ƒôº', label: 'Newsletter' },
    { id: 'comments',        icon: '≡ƒÆ¼', label: 'Comments' },
    { id: 'reviews-pending', icon: 'Γ¡É', label: 'Reviews Pending' },
    { id: 'referrals',       icon: '≡ƒöù', label: 'Referrals' },
  ]
  return (
    <div className="w-[220px] min-h-screen flex-shrink-0 bg-[#7B2FBE] flex flex-col">
      <div className="px-4 py-5 border-b border-white/15 text-center">
