          <Btn onClick={() => setAdding(!adding)} variant={adding ? 'ghost' : 'primary'} className="px-4 py-2 text-sm">{adding ? 'Cancel' : '+ Add Testimonial'}</Btn>
        </div>
        {adding && (
          <div className="mb-4 rounded-2xl border border-[#7B2FBE]/20 bg-[#f0efff] p-4">
