                  <div className="flex gap-1">
                    {[1,2,3,4,5].map(s => (
                      <button key={s} onClick={() => updateT(i, 'rating', s)}
                        className={`rounded-xl px-2 text-[11px] ${s <= (t.rating||5) ? 'bg-amber-400 text-slate-900' : 'bg-slate-200 text-slate-500'}`}>
