              <Btn onClick={() => set('stats', [...d.stats, { value: '0', label: 'New Stat' }])} className="px-4 py-2 text-sm">+ Add Stat</Btn>
            </div>
          </div>
          <p className="text-sm text-slate-500 mb-4">Purple stats bar shown just below the hero banner.</p>
