function ActivityLogView({ token }) {
  const [logs, setLogs] = useState([])
  const [loading, setLoading] = useState(true)

  function load() {
    setLoading(true)
    fetch('/api/admin/activity-log', { headers: authH(token) })
      .then(r => r.ok ? r.json() : [])
      .then(d => { setLogs(Array.isArray(d) ? d : []); setLoading(false) })
      .catch(() => setLoading(false))
  }

  useEffect(() => { load() }, [])

  return (
    <div>
      <div className="mb-5 flex flex-wrap items-center justify-between gap-3">
        <div>
          <h2 className="text-[20px] font-extrabold text-slate-900 mb-1">≡ƒô£ Activity Log</h2>
          <p className="text-sm text-slate-500 m-0">Recent admin actions ΓÇö last 200 entries</p>
        </div>
        <Btn variant="ghost" onClick={load}>Γå╗ Refresh</Btn>
      </div>
      {loading ? (
        <Card><p className="m-0 text-sm text-slate-500">LoadingΓÇª</p></Card>
      ) : logs.length === 0 ? (
        <Card className="text-center p-12">
          <div className="text-4xl mb-3">≡ƒô£</div>
          <p className="text-base font-semibold text-slate-900 mb-1">No activity recorded yet</p>
          <p className="text-sm text-slate-500 m-0">Activity will appear here as you manage content and settings.</p>
        </Card>
      ) : (
        <Card className="p-0 overflow-hidden">
          <div className="overflow-x-auto">
            <table className="min-w-full border-collapse text-sm">
