      setError('Failed to submit. Please try again.')
    }
    setSubmitting(false)
  }

  const fmt = ts => { try { return new Date(ts).toLocaleDateString('en-NG', { year: 'numeric', month: 'short', day: 'numeric' }) } catch { return '' } }

  return (
    <div className="mt-16 border-t border-slate-200 pt-10">
      <h3 className="text-xl font-bold text-slate-900">≡ƒÆ¼ Comments {comments.length > 0 && `(${comments.length})`}</h3>

