        .blog-content img { max-width: 100%; border-radius: 1rem; margin: 1.2rem 0; }
        .blog-content ul, .blog-content ol { padding-left: 1.2rem; margin: 0 0 1.1rem; line-height: 1.8; }
        .blog-content blockquote { border-left: 0.3rem solid ${PRI}; padding: 1rem 1.2rem; margin: 1.25rem 0; background: #f9f5ff; border-radius: 0 1rem 1rem 0; color: #555; font-style: italic; }
        .blog-content pre, .blog-content code { background: #f4f4f4; padding: 0.2rem 0.5rem; border-radius: 0.4rem; font-size: 0.95rem; }
        .blog-content strong { color: #1a1a1a; }
      `}</style>
    </article>
  )
}

import { useState, useEffect } from 'react'
import { useNavigate } from 'react-router-dom'
import { ALL_PRODUCTS } from '../data/products'
import { PRODUCT_IMAGES } from '../data/productImages'
import { useSEO } from '../hooks/useSEO'

const PRI = '#7B2FBE'

const COMPARE_KEY = 'sbm_compare'

function getCompareList() {
  try { return JSON.parse(localStorage.getItem(COMPARE_KEY) || '[]') } catch { return [] }
}
export function toggleCompare(slug) {
  const list = getCompareList()
  const next = list.includes(slug) ? list.filter(s => s !== slug) : list.length >= 4 ? list : [...list, slug]
  localStorage.setItem(COMPARE_KEY, JSON.stringify(next))
  window.dispatchEvent(new Event('sbm-compare-change'))
  return next
}
export function isInCompare(slug) { return getCompareList().includes(slug) }

const ATTR_ROWS = [
  { key: 'category', label: 'Category' },
  { key: 'description', label: 'Description' },
  { key: 'price', label: 'Starting Price', fmt: v => `Γéª${Number(v).toLocaleString()}` },
  { key: 'moq', label: 'Min. Order Qty', fmt: v => v ? `${v} pcs` : '1 pc' },
  { key: 'deliveryDays', label: 'Delivery', fmt: v => v ? `${v} business days` : '1ΓÇô3 days' },
]

export default function ComparisonPage() {
  useSEO({ title: 'Compare Products ΓÇö Sleekblue Media Houz', description: 'Compare our printing and branding products side by side to find the best option for your needs.' })
  const navigate = useNavigate()
  const [slugs, setSlugs] = useState(getCompareList)
  const [overrides, setOverrides] = useState({})

  useEffect(() => {
    const onUpdate = () => setSlugs(getCompareList())
    window.addEventListener('sbm-compare-change', onUpdate)
    return () => window.removeEventListener('sbm-compare-change', onUpdate)
  }, [])

  useEffect(() => {
    fetch('/api/products')
      .then(r => r.ok ? r.json() : {})
      .then(d => setOverrides(d.productOverrides || {}))
      .catch(() => {})
  }, [])

  const products = slugs.map(slug => {
    const base = ALL_PRODUCTS.find(p => p.slug === slug)
    if (!base) return null
    return { ...base, ...(overrides[slug] || {}) }
  }).filter(Boolean)

  if (slugs.length === 0) {
    return (
      <section style={{ background: '#FAF3E8', minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center', fontFamily: "'HubotSans', sans-serif", padding: '40px 24px' }}>
        <div style={{ textAlign: 'center', maxWidth: '480px' }}>
          <div style={{ fontSize: '56px', marginBottom: '20px' }}>≡ƒôè</div>
          <h1 style={{ fontSize: '26px', fontWeight: 800, color: '#1a1a1a', marginBottom: '12px' }}>No products to compare</h1>
          <p style={{ color: '#888', fontSize: '14px', marginBottom: '28px', lineHeight: 1.6 }}>
            Browse our store and click the <strong>Compare</strong> button on products to add them here. You can compare up to 4 products at once.
          </p>
          <button onClick={() => navigate('/store')}
            style={{ background: PRI, color: '#fff', border: 'none', borderRadius: '10px', padding: '12px 28px', fontSize: '14px', fontWeight: 700, cursor: 'pointer' }}>
            Browse Store
          </button>
        </div>
      </section>
    )
  }

  return (
    <section style={{ background: '#FAF3E8', minHeight: '100vh', padding: '40px 24px 80px', fontFamily: "'HubotSans', sans-serif" }}>
      <div style={{ maxWidth: '1100px', margin: '0 auto' }}>
        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '28px', flexWrap: 'wrap', gap: '12px' }}>
          <div>
            <h1 style={{ fontSize: '28px', fontWeight: 800, color: '#1a1a1a', margin: '0 0 6px' }}>Product Comparison</h1>
            <p style={{ fontSize: '13px', color: '#888', margin: 0 }}>Comparing {products.length} product{products.length !== 1 ? 's' : ''} ΓÇö up to 4 allowed</p>
          </div>
          <div style={{ display: 'flex', gap: '10px' }}>
            <button onClick={() => navigate('/store')}
              style={{ padding: '9px 20px', background: '#fff', border: `1.5px solid ${PRI}`, borderRadius: '8px', color: PRI, fontWeight: 700, fontSize: '13px', cursor: 'pointer' }}>
              + Add More
            </button>
            <button onClick={() => { localStorage.setItem(COMPARE_KEY, '[]'); setSlugs([]) }}
              style={{ padding: '9px 20px', background: '#fef2f2', border: '1.5px solid #fca5a5', borderRadius: '8px', color: '#dc2626', fontWeight: 700, fontSize: '13px', cursor: 'pointer' }}>
              Clear All
            </button>
          </div>
        </div>

        <div style={{ overflowX: 'auto', borderRadius: '16px', boxShadow: '0 2px 16px rgba(0,0,0,0.08)' }}>
          <table style={{ width: '100%', borderCollapse: 'collapse', background: '#fff', minWidth: '600px' }}>
            {/* Product header row */}
            <thead>
              <tr>
                <th style={{ width: '180px', padding: '20px 18px', background: '#f9f5ff', borderRight: '1px solid #f0f0f0', textAlign: 'left', fontSize: '12px', color: '#888', textTransform: 'uppercase', letterSpacing: '0.5px', fontWeight: 700 }}>
                  Feature
                </th>
                {products.map(p => (
                  <th key={p.slug} style={{ padding: '20px 18px', background: '#f9f5ff', borderRight: '1px solid #f0f0f0', textAlign: 'center', minWidth: '200px' }}>
                    <div style={{ position: 'relative', display: 'inline-block' }}>
                      <button onClick={() => { const next = slugs.filter(s => s !== p.slug); localStorage.setItem(COMPARE_KEY, JSON.stringify(next)); setSlugs(next) }}
                        title="Remove from comparison"
                        style={{ position: 'absolute', top: -8, right: -8, width: 22, height: 22, borderRadius: '50%', border: 'none', background: '#fef2f2', color: '#dc2626', cursor: 'pointer', fontSize: '12px', fontWeight: 700, display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 1 }}>├ù</button>
                      <div style={{ width: '90px', height: '90px', borderRadius: '10px', overflow: 'hidden', background: '#f0e8ff', margin: '0 auto 10px' }}>
                        {PRODUCT_IMAGES[p.slug]?.[0]
                          ? <img src={PRODUCT_IMAGES[p.slug][0]} alt={p.name} style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
                          : <div style={{ width: '100%', height: '100%', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '32px' }}>≡ƒû¿∩╕Å</div>
                        }
                      </div>
                      <p style={{ fontSize: '14px', fontWeight: 700, color: '#1a1a1a', margin: '0 0 4px' }}>{p.name}</p>
                      <button onClick={() => navigate(`/store/${p.slug}`)}
                        style={{ background: PRI, color: '#fff', border: 'none', borderRadius: '7px', padding: '6px 14px', fontSize: '12px', fontWeight: 700, cursor: 'pointer', marginTop: '4px' }}>
                        View Product ΓåÆ
                      </button>
                    </div>
                  </th>
                ))}
              </tr>
            </thead>
            <tbody>
              {ATTR_ROWS.map((row, ri) => (
                <tr key={row.key} style={{ background: ri % 2 === 0 ? '#fff' : '#faf5ff' }}>
                  <td style={{ padding: '14px 18px', fontSize: '13px', fontWeight: 700, color: '#555', borderRight: '1px solid #f0f0f0', borderTop: '1px solid #f0f0f0' }}>
                    {row.label}
                  </td>
                  {products.map(p => {
                    const val = p[row.key]
                    const display = row.fmt ? (val != null ? row.fmt(val) : 'ΓÇö') : (val || 'ΓÇö')
                    return (
                      <td key={p.slug} style={{ padding: '14px 18px', fontSize: '13.5px', color: '#333', textAlign: 'center', borderRight: '1px solid #f0f0f0', borderTop: '1px solid #f0f0f0', lineHeight: 1.5 }}>
                        {display}
                      </td>
                    )
                  })}
                </tr>
              ))}
              {/* Action row */}
              <tr style={{ borderTop: '2px solid #e0d6f5' }}>
                <td style={{ padding: '18px', background: '#f9f5ff', borderRight: '1px solid #f0f0f0' }} />
                {products.map(p => (
                  <td key={p.slug} style={{ padding: '18px', textAlign: 'center', background: '#f9f5ff', borderRight: '1px solid #f0f0f0' }}>
                    <button onClick={() => navigate(`/store/${p.slug}`)}
                      style={{ background: PRI, color: '#fff', border: 'none', borderRadius: '8px', padding: '11px 22px', fontSize: '13px', fontWeight: 700, cursor: 'pointer', width: '100%' }}>
                      Order Now
                    </button>
                    <button onClick={() => navigate('/quote')}
                      style={{ background: '#fff', color: PRI, border: `1.5px solid ${PRI}`, borderRadius: '8px', padding: '9px 22px', fontSize: '13px', fontWeight: 700, cursor: 'pointer', width: '100%', marginTop: '8px' }}>
                      Get Quote
                    </button>
                  </td>
                ))}
              </tr>
            </tbody>
          </table>
        </div>

        <p style={{ textAlign: 'center', color: '#aaa', fontSize: '12px', marginTop: '24px' }}>
          Can't decide? <a href="/quote" style={{ color: PRI, fontWeight: 600, textDecoration: 'none' }}>Request a custom quote</a> and our team will help you choose the right product.
        </p>
      </div>
    </section>
  )
}

import { useState, useEffect } from 'react'
import { useParams, useNavigate } from 'react-router-dom'
import { useCart } from '../context/CartContext'
import { ALL_PRODUCTS, getProductDetails, calcStickerPrice, getStickerPriceTable, STICKER_SIZE_PRICES } from '../data/products'
import { PRODUCT_IMAGES, STICKER_SIZE_IMAGES } from '../data/productImages'
import { useSEO } from '../hooks/useSEO'
import { trackProductView } from '../hooks/useAnalytics'
import Breadcrumb from '../components/Breadcrumb'

const thumbColors = ['#C8C8C8', '#B0B0B0', '#D0D0D0']

function fmt(n) {
  return 'Γéª' + Math.round(n).toLocaleString()
}

function getYoutubeId(url) {
  const m = url.match(/(?:youtube\.com\/(?:watch\?v=|embed\/)|youtu\.be\/)([^&?/]+)/)
  return m ? m[1] : ''
}

// Return the nearest standard sticker size for a given area (w ├ù h)
function findNearestSize(w, h) {
  const area = w * h
  let nearest = '3x3"'
  let minDiff = Infinity
  Object.keys(STICKER_SIZE_PRICES).forEach(sizeKey => {
    const nums = sizeKey.match(/[\d.]+/g)
    if (nums && nums.length >= 2) {
      const a = parseFloat(nums[0]) * parseFloat(nums[1])
      const diff = Math.abs(a - area)
      if (diff < minDiff) { minDiff = diff; nearest = sizeKey }
    }
  })
  return nearest
}

export default function ProductPage() {
  const { slug } = useParams()
  const navigate = useNavigate()
  const { addToCart } = useCart()

  const baseProduct = ALL_PRODUCTS.find(p => p.slug === slug) || ALL_PRODUCTS[7]

  // Dynamic SEO per product page
  const seoKey = slug === 'die-cut-stickers' ? 'dieCut' : slug === 'flex-banner' ? 'flexBanner' : slug === 'product-labels' ? 'labels' : slug
  useSEO(seoKey, { title: `${baseProduct?.name || 'Product'} ΓÇö Sleekblue Media Houz`, description: `Order ${baseProduct?.name || 'custom printing'} from Sleekblue Media Houz. Premium quality, fast delivery across Nigeria.` })
  const baseDetails = getProductDetails(baseProduct.slug)

  useEffect(() => {
    const existing = document.getElementById('product-schema')
    if (existing) existing.remove()
    const pricingText = baseDetails?.pricing?.startingAt
      ? String(baseDetails.pricing.startingAt).replace(/[^0-9.]/g, '')
      : null
    const schema = {
      '@context': 'https://schema.org',
      '@type': 'Product',
      name: baseProduct?.name || 'Custom Printing',
      description: `Order ${baseProduct?.name || 'custom printing'} from Sleekblue Media Houz. Premium quality, fast delivery across Nigeria. ${baseProduct?.tagline || ''}`.trim(),
      brand: { '@type': 'Brand', name: 'Sleekblue Media Houz' },
      url: `https://sleekbluemediahouz.com/store/${slug}`,
      image: `https://sleekbluemediahouz.com/store/${slug}`,
      offers: {
        '@type': baseProduct?.isDieCut ? 'AggregateOffer' : 'Offer',
        ...(baseProduct?.isDieCut
          ? { lowPrice: '3000', highPrice: '80000', offerCount: Object.keys(STICKER_SIZE_PRICES).length }
          : { price: pricingText || '5000' }
        ),
        priceCurrency: 'NGN',
        availability: 'https://schema.org/InStock',
        seller: { '@type': 'Organization', name: 'Sleekblue Media Houz' },
      },
    }
    const tag = document.createElement('script')
    tag.id = 'product-schema'
    tag.type = 'application/ld+json'
    tag.textContent = JSON.stringify(schema)
    document.head.appendChild(tag)
    const bcTag = document.createElement('script')
    bcTag.id = 'product-bc-schema'; bcTag.type = 'application/ld+json'
    bcTag.textContent = JSON.stringify({
      '@context': 'https://schema.org', '@type': 'BreadcrumbList',
      itemListElement: [
        { '@type': 'ListItem', position: 1, name: 'Home', item: 'https://sleekbluemediahouz.com/' },
        { '@type': 'ListItem', position: 2, name: 'Store', item: 'https://sleekbluemediahouz.com/store' },
        { '@type': 'ListItem', position: 3, name: baseProduct?.name || 'Product', item: `https://sleekbluemediahouz.com/store/${slug}` },
      ],
    })
    document.head.appendChild(bcTag)
    return () => {
      const el = document.getElementById('product-schema'); if (el) el.remove()
      const bc = document.getElementById('product-bc-schema'); if (bc) bc.remove()
    }
  }, [slug, baseProduct, baseDetails])

  // Admin overrides ΓÇö fetched from server, applied on top of static data
  const [adminOverride, setAdminOverride] = useState(null)
  const [uploadedImages, setUploadedImages] = useState({})
  const [stickerImages, setStickerImages] = useState({})
  const [variantImages, setVariantImages] = useState({})
  useEffect(() => {
    trackProductView(baseProduct.slug, baseProduct.name)
    fetch(`/api/products/${baseProduct.slug}`)
      .then(r => r.ok ? r.json() : null)
      .then(data => { if (data) setAdminOverride(data) })
      .catch(() => {})
    fetch('/api/product-images')
      .then(r => r.ok ? r.json() : {})
      .then(d => setUploadedImages(d || {}))
      .catch(() => {})
    fetch('/api/sticker-images')
      .then(r => r.ok ? r.json() : {})
      .then(d => setStickerImages(d || {}))
      .catch(() => {})
    fetch('/api/product-variant-images')
      .then(r => r.ok ? r.json() : {})
      .then(d => setVariantImages(d || {}))
      .catch(() => {})
    fetch(`/api/product/views/${baseProduct.slug}`)
      .then(r => r.ok ? r.json() : { views7d: 0 })
      .then(d => setViews7d(d.views7d || 0))
      .catch(() => {})
    try { setInWishlist((JSON.parse(localStorage.getItem('sbm_wishlist') || '[]')).includes(baseProduct.slug)) } catch {}
  }, [baseProduct.slug])

  const product = adminOverride ? { ...baseProduct, ...adminOverride } : baseProduct
  const details = adminOverride
    ? { ...baseDetails, ...(adminOverride.description ? { description: adminOverride.description } : {}), ...(adminOverride.features ? { features: adminOverride.features } : {}), ...(adminOverride.badge ? { badge: adminOverride.badge } : {}) }
    : baseDetails
  const isDieCut = !!baseProduct.isDieCut

  const sizes = product.sizes || ['Standard']
  const [selectedSize, setSelectedSize] = useState(sizes[0])
  const [customQty, setCustomQty] = useState(isDieCut ? 100 : (product.priceTable[0]?.qty || 1))
  const [selectedThumb, setSelectedThumb] = useState(0)
  const [added, setAdded] = useState(false)
  const [artworkFile, setArtworkFile] = useState(null)
  const [artworkUploading, setArtworkUploading] = useState(false)
  const [artworkDone, setArtworkDone] = useState(false)
  const [recentlyViewed, setRecentlyViewed] = useState([])
  const [views7d, setViews7d] = useState(0)
  const [inWishlist, setInWishlist] = useState(false)

  function toggleWishlist(e) {
    e?.stopPropagation()
    try {
      const list = JSON.parse(localStorage.getItem('sbm_wishlist') || '[]')
      const next = list.includes(slug) ? list.filter(s => s !== slug) : [...list, slug]
      localStorage.setItem('sbm_wishlist', JSON.stringify(next))
      setInWishlist(next.includes(slug))
    } catch {}
  }

  // Custom size state (only for die-cut stickers)
  const [customWidth, setCustomWidth] = useState(3)
  const [customHeight, setCustomHeight] = useState(3)

  // Reset thumbnail when navigating between products
  useEffect(() => {
    setSelectedThumb(0)
    setSelectedSize(sizes[0])
    setCustomQty(isDieCut ? 100 : (product.priceTable[0]?.qty || 1))
    setAdminOverride(null)
  }, [slug])

  // Track recently viewed & load others
  useEffect(() => {
    try {
      const KEY = 'sbm_recently_viewed'
      const existing = JSON.parse(localStorage.getItem(KEY) || '[]')
      setRecentlyViewed(existing.filter(p => p.slug !== slug).slice(0, 6))
      const entry = { slug: product.slug, name: product.name, img: PRODUCT_IMAGES[product.slug]?.[0] || null }
      localStorage.setItem(KEY, JSON.stringify([entry, ...existing.filter(p => p.slug !== slug)].slice(0, 10)))
    } catch {}
  }, [slug])

  async function uploadArtwork() {
    if (!artworkFile) return
    setArtworkUploading(true)
    try {
      const fd = new FormData(); fd.append('artwork', artworkFile)
      const res = await fetch('/api/upload/artwork', { method: 'POST', body: fd })
      const data = await res.json()
      if (data.ok) { setArtworkDone(true); setTimeout(() => { setArtworkDone(false); setArtworkFile(null) }, 4000) }
    } catch {}
    setArtworkUploading(false)
  }

  // For die-cut with Custom size, resolve to nearest standard for pricing
  const effectiveSize = (isDieCut && selectedSize === 'Custom')
    ? findNearestSize(customWidth, customHeight)
    : selectedSize

  // Product images ΓÇö variant-specific > product-level uploaded > static fallback
  const uploadedForSlug = uploadedImages[product.slug] || []
  const serverStickerImgs = stickerImages[effectiveSize] || []
  const variantSpecificImgs = !isDieCut ? (variantImages[product.slug]?.[selectedSize] || []) : []
  const productImgs = isDieCut
    ? (serverStickerImgs.length > 0 ? serverStickerImgs : (STICKER_SIZE_IMAGES[effectiveSize] || []))
    : (variantSpecificImgs.length > 0 ? variantSpecificImgs : (uploadedForSlug.length > 0 ? uploadedForSlug : (PRODUCT_IMAGES[product.slug] || [])))
  const hasImages = productImgs.length > 0
  const displayImgs = hasImages ? productImgs : null

  // --- Pricing logic (variant-aware) ---
  const variantPriceTable = (!isDieCut && adminOverride?.variantPrices?.[selectedSize] && adminOverride.variantPrices[selectedSize].length > 0)
    ? adminOverride.variantPrices[selectedSize]
    : null

  function getPrice(qty) {
    if (isDieCut) return calcStickerPrice(effectiveSize, qty).total
    const table = variantPriceTable || product.priceTable || []
    if (table.length === 0) return product.price * qty
    let unit = table[0].unitPrice
    for (const row of table) { if (qty >= row.qty) unit = row.unitPrice }
    return unit * qty
  }

  const currentTotal = getPrice(customQty)
  const currentUnit = customQty > 0 ? currentTotal / customQty : 0

  // Die-cut: discount info
  const stickerCalc = isDieCut ? calcStickerPrice(effectiveSize, customQty) : null
  const discountPct = stickerCalc ? Math.round(stickerCalc.discountRate * 100) : 0

  // Price table rows for display
  const activePriceTable = variantPriceTable || product.priceTable || []
  const priceRows = isDieCut
    ? getStickerPriceTable(effectiveSize)
    : activePriceTable.map(row => ({ qty: row.qty, label: row.qty.toLocaleString(), total: row.unitPrice * row.qty, unitPrice: row.unitPrice, discountRate: 0 }))

  function handleAddToCart() {
    addToCart({
      id: product.id,
      name: product.name,
      size: selectedSize === 'Custom' ? `${customWidth}├ù${customHeight}"` : selectedSize,
      quantity: customQty,
      price: Math.round(currentTotal / customQty),
      slug: product.slug,
    })
    setAdded(true)
    setTimeout(() => setAdded(false), 2200)
  }

  function handleCheckout() {
    handleAddToCart()
    navigate('/cart')
  }

  function clickQtyRow(qty) {
    setCustomQty(qty)
  }

  const STICKER_SLUGS = ['die-cut-stickers','product-labels','transparent-stickers','holographic-stickers','chrome-stickers','vinyl-roll-labels','seal-stickers','bumper-stickers','barcode-labels','paper-stickers']
  const isSticker = product.category === 'Label Stickers' || STICKER_SLUGS.includes(product.slug)
  const similarProducts = isSticker
    ? ALL_PRODUCTS.filter(p => STICKER_SLUGS.includes(p.slug) && p.id !== product.id).slice(0, 8)
    : ALL_PRODUCTS.filter(p => p.category === product.category && p.id !== product.id).slice(0, 8)

  // Popular badge logic for die-cut sizes
  function getSizeBadge(size) {
    if (!isDieCut) return null
    if (size === '3x3"') return { label: '≡ƒöÑ #1 Popular', bg: '#FF6B00', color: '#fff' }
    if (size === '3x4"') return { label: 'Popular', bg: '#7B2FBE', color: '#fff' }
    return null
  }

  return (
    <section style={{ background: '#FAF3E8', padding: '28px 16px 50px', minHeight: '100vh' }}>
      <div style={{ maxWidth: '1280px', margin: '0 auto' }}>

        <Breadcrumb crumbs={[{ label: 'Home', href: '/' }, { label: 'Store', href: '/store' }, { label: product.name }]} />

        <div className="product-layout" style={{ display: 'grid', gridTemplateColumns: '240px 1fr 280px', gap: '20px', marginBottom: '40px', alignItems: 'start' }}>

          {/* LEFT ΓÇö image gallery */}
          <div>
            <div style={{ background: displayImgs ? 'transparent' : thumbColors[selectedThumb], borderRadius: '12px', border: '3px solid #7B2FBE', width: '100%', aspectRatio: '3/4', marginBottom: '10px', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: displayImgs ? 'flex-start' : 'flex-end', paddingBottom: displayImgs ? 0 : '16px', position: 'relative', overflow: 'hidden' }}>
              {details.badge && (
                <div style={{ position: 'absolute', top: '12px', left: '12px', background: '#7B2FBE', color: '#fff', padding: '4px 12px', borderRadius: '20px', fontSize: '11px', fontWeight: 700, fontFamily: "'HubotSans', sans-serif", zIndex: 2 }}>{details.badge}</div>
              )}
              {displayImgs ? (
                <img
                  key={selectedThumb}
                  src={displayImgs[Math.min(selectedThumb, displayImgs.length - 1)]}
                  alt={product.name}
                  loading="lazy"
                  decoding="async"
                  style={{ width: '100%', height: '100%', objectFit: 'cover', display: 'block', borderRadius: '9px' }}
                />
              ) : (
                <div style={{ textAlign: 'center', padding: '0 12px' }}>
                  <p style={{ fontWeight: 700, fontSize: '14px', color: '#1a1a1a', fontFamily: "'HubotSans', sans-serif" }}>{product.name}</p>
                  <p style={{ fontWeight: 700, fontSize: '15px', color: '#7B2FBE', fontFamily: "'HubotSans', sans-serif" }}>{fmt(currentTotal)}</p>
                  <p style={{ fontSize: '11px', color: '#555' }}>for {customQty.toLocaleString()} pcs</p>
                </div>
              )}
            </div>

            {/* Thumbnails */}
            {displayImgs ? (
              <div style={{ display: 'flex', gap: '6px', flexWrap: 'wrap', marginTop: '2px' }}>
                {displayImgs.map((img, i) => {
                  const thumbSize = displayImgs.length > 4 ? '44px' : displayImgs.length > 3 ? '52px' : '70px'
                  return (
                    <div key={i} onClick={() => setSelectedThumb(i)}
                      style={{ width: thumbSize, height: thumbSize, borderRadius: '6px', border: selectedThumb === i ? '2.5px solid #7B2FBE' : '1.5px solid #ddd', cursor: 'pointer', overflow: 'hidden', background: '#ddd', flexShrink: 0 }}>
                      <img src={img} alt={`View ${i + 1}`} loading="lazy" decoding="async"
                        style={{ width: '100%', height: '100%', objectFit: 'cover', display: 'block' }} />
                    </div>
                  )
                })}
              </div>
            ) : (
              <div style={{ display: 'flex', gap: '8px' }}>
                {thumbColors.map((color, i) => (
                  <div key={i} onClick={() => setSelectedThumb(i)}
                    style={{ flex: 1, aspectRatio: '1', background: color, borderRadius: '6px', border: selectedThumb === i ? '2.5px solid #7B2FBE' : '1px solid #ddd', cursor: 'pointer' }} />
                ))}
              </div>
            )}

            {/* Product video */}
            {adminOverride?.videoUrl && (
              <div style={{ marginTop: '10px', borderRadius: '10px', overflow: 'hidden' }}>
                {(adminOverride.videoUrl.includes('youtube') || adminOverride.videoUrl.includes('youtu.be')) ? (
                  <iframe src={`https://www.youtube.com/embed/${getYoutubeId(adminOverride.videoUrl)}`}
                    title="Product video"
                    style={{ width: '100%', aspectRatio: '16/9', border: 'none', borderRadius: '10px', display: 'block' }}
                    allowFullScreen />
                ) : (
                  <video src={adminOverride.videoUrl} controls
                    style={{ width: '100%', borderRadius: '10px', display: 'block' }} />
                )}
              </div>
            )}
          </div>

          {/* CENTER ΓÇö details & pricing */}
          <div style={{ background: '#fff', borderRadius: '12px', padding: '20px', boxShadow: '0 1px 6px rgba(0,0,0,0.06)' }}>
            <div style={{ display: 'flex', alignItems: 'flex-start', justifyContent: 'space-between', gap: '8px', marginBottom: '4px' }}>
              <h1 style={{ fontSize: '18px', fontWeight: 800, color: '#1a1a1a', margin: 0, fontFamily: "'HubotSans', sans-serif" }}>{product.name}</h1>
              <button onClick={toggleWishlist} title={inWishlist ? 'Remove from wishlist' : 'Save for later'}
                style={{ flexShrink: 0, background: inWishlist ? '#fef2f2' : '#f5f0ff', border: `1.5px solid ${inWishlist ? '#fca5a5' : '#e0d6f5'}`, borderRadius: '8px', padding: '6px 10px', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '4px', color: inWishlist ? '#dc2626' : '#7B2FBE', fontWeight: 600, fontSize: '12px', fontFamily: "'HubotSans', sans-serif" }}>
                {inWishlist ? 'Γ¥ñ∩╕Å Saved' : '≡ƒñì Save'}
              </button>
            </div>
            <p style={{ fontSize: '12px', color: '#888', marginBottom: views7d >= 3 ? '6px' : '16px', fontFamily: "'HubotSans', sans-serif" }}>{product.category}</p>
            {views7d >= 3 && (
              <div style={{ fontSize: '12px', color: '#e53e3e', fontWeight: 600, marginBottom: '14px', display: 'flex', alignItems: 'center', gap: '4px', fontFamily: "'HubotSans', sans-serif" }}>
                ≡ƒöÑ {views7d} people viewed this in the past 7 days
              </div>
            )}

            {/* Size selector */}
            <p style={{ fontSize: '12.5px', fontWeight: 700, color: '#333', marginBottom: '8px', fontFamily: "'HubotSans', sans-serif" }}>
              {isDieCut ? 'Size (inches):' : 'Size / Type:'}
            </p>
            <div style={{ display: 'flex', gap: '8px', marginBottom: '18px', flexWrap: 'wrap', alignItems: 'flex-start' }}>
              {sizes.map(size => {
                const badge = getSizeBadge(size)
                const isSelected = selectedSize === size
                return (
                  <div key={size} style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '3px' }}>
                    <button
                      onClick={() => {
                        setSelectedSize(size)
                        setSelectedThumb(0)
                        setCustomQty(isDieCut ? 100 : (product.priceTable[0]?.qty || 1))
                      }}
                      style={{
                        padding: '6px 14px',
                        borderRadius: '20px',
                        border: badge && !isSelected ? `1.5px solid ${badge.bg}` : 'none',
                        background: isSelected ? '#7B2FBE' : (badge ? '#FFF0E8' : '#EDEDED'),
                        color: isSelected ? '#fff' : (badge ? badge.bg : '#333'),
                        fontSize: '12.5px',
                        fontWeight: 600,
                        cursor: 'pointer',
                        fontFamily: "'HubotSans', sans-serif",
                        transition: 'all 0.15s',
                        whiteSpace: 'nowrap',
                      }}
                    >
                      {size}
                    </button>
                    {badge && (
                      <span style={{ fontSize: '9px', background: isSelected ? '#7B2FBE' : badge.bg, color: '#fff', padding: '1px 6px', borderRadius: '8px', fontWeight: 700, lineHeight: 1.5 }}>
                        {badge.label}
                      </span>
                    )}
                  </div>
                )
              })}
            </div>

            {/* Custom size inputs ΓÇö shown only for die-cut + Custom */}
            {isDieCut && selectedSize === 'Custom' && (
              <div style={{ background: '#f8f5ff', border: '1.5px solid #d4b5ff', borderRadius: '10px', padding: '14px 16px', marginBottom: '18px' }}>
                <p style={{ fontSize: '12.5px', fontWeight: 700, color: '#333', marginBottom: '10px', fontFamily: "'HubotSans', sans-serif" }}>
                  Enter your custom size (inches):
                </p>
                <div style={{ display: 'flex', alignItems: 'center', gap: '10px', flexWrap: 'wrap' }}>
                  <div>
                    <label style={{ fontSize: '11px', color: '#666', display: 'block', marginBottom: '4px', fontFamily: "'HubotSans', sans-serif" }}>Width (in)</label>
                    <input
                      type="number" min="0.5" step="0.5" value={customWidth}
                      onChange={e => setCustomWidth(Math.max(0.5, parseFloat(e.target.value) || 0.5))}
                      style={{ width: '72px', padding: '7px 10px', border: '1.5px solid #ccc', borderRadius: '8px', fontSize: '13px', textAlign: 'center', fontFamily: "'HubotSans', sans-serif", outline: 'none' }}
                    />
                  </div>
                  <span style={{ fontSize: '18px', color: '#666', marginTop: '14px' }}>├ù</span>
                  <div>
                    <label style={{ fontSize: '11px', color: '#666', display: 'block', marginBottom: '4px', fontFamily: "'HubotSans', sans-serif" }}>Height (in)</label>
                    <input
                      type="number" min="0.5" step="0.5" value={customHeight}
                      onChange={e => setCustomHeight(Math.max(0.5, parseFloat(e.target.value) || 0.5))}
                      style={{ width: '72px', padding: '7px 10px', border: '1.5px solid #ccc', borderRadius: '8px', fontSize: '13px', textAlign: 'center', fontFamily: "'HubotSans', sans-serif", outline: 'none' }}
                    />
                  </div>
                  <div style={{ marginTop: '14px', fontSize: '12px', color: '#555', fontFamily: "'HubotSans', sans-serif" }}>
                    ΓåÆ Priced as <strong style={{ color: '#7B2FBE' }}>{effectiveSize}</strong>
                  </div>
                </div>
                <p style={{ fontSize: '11px', color: '#888', marginTop: '8px', lineHeight: 1.5, fontFamily: "'HubotSans', sans-serif" }}>
                  Price estimate based on nearest standard size. Our team will confirm exact pricing.
                </p>
              </div>
            )}

            {/* Price table */}
            <p style={{ fontSize: '12.5px', fontWeight: 700, color: '#333', marginBottom: '8px', fontFamily: "'HubotSans', sans-serif" }}>
              Price Table{isDieCut && selectedSize === 'Custom' && <span style={{ fontSize: '11px', color: '#7B2FBE', fontWeight: 400 }}> (for {effectiveSize})</span>}
              <span style={{ fontSize: '11px', color: '#999', fontWeight: 400 }}> (click a row to set quantity)</span>
            </p>
            <div style={{ borderRadius: '8px', overflow: 'hidden', border: '1px solid #eee', marginBottom: '18px' }}>
              <table style={{ width: '100%', borderCollapse: 'collapse' }}>
                <thead>
                  <tr style={{ background: '#f5f5f5' }}>
                    <th style={{ padding: '9px 14px', textAlign: 'left', fontSize: '12px', color: '#555', fontWeight: 700, fontFamily: "'HubotSans', sans-serif" }}>Qty (pcs)</th>
                    <th style={{ padding: '9px 14px', textAlign: 'left', fontSize: '12px', color: '#555', fontWeight: 700, fontFamily: "'HubotSans', sans-serif" }}>Total Price</th>
                    <th style={{ padding: '9px 14px', textAlign: 'left', fontSize: '12px', color: '#555', fontWeight: 700, fontFamily: "'HubotSans', sans-serif" }}>Unit Price</th>
                    {isDieCut && <th style={{ padding: '9px 14px', textAlign: 'left', fontSize: '12px', color: '#555', fontWeight: 700, fontFamily: "'HubotSans', sans-serif" }}>Discount</th>}
                  </tr>
